import os
import sys
from openai import OpenAI

SYSTEM_INSTRUCTIONS = (
    "You are a customer support assistant for our company. "
    "Be helpful, concise, and accurate. Ask clarifying questions when needed. "
    "If you don't know, say so and offer next steps."
)

MODEL = os.getenv("OPENAI_MODEL", "gpt-4.1-mini")

def get_client() -> OpenAI:
    api_key = os.getenv("OPENAI_API_KEY")
    if not api_key:
        raise RuntimeError("OPENAI_API_KEY environment variable is required.")
    return OpenAI(api_key=api_key)

def build_prompt(user_input: str) -> str:
    user_input = user_input.strip()
    return f"{SYSTEM_INSTRUCTIONS}\n\nUser: {user_input}\nAssistant:"

def chat_once(client: OpenAI, user_input: str) -> str:
    prompt = build_prompt(user_input)
    resp = client.responses.create(
        model=MODEL,
        input=prompt,
    )
    return resp.output_text.strip()

def repl() -> None:
    client = get_client()
    print("Customer Support Chatbot (type 'exit' to quit)")
    while True:
        try:
            user_input = input("> ")
        except (EOFError, KeyboardInterrupt):
            print()
            break

        if not user_input.strip():
            continue
        if user_input.strip().lower() in {"exit", "quit"}:
            break

        try:
            answer = chat_once(client, user_input)
        except Exception as e:
            print(f"Error: {e}", file=sys.stderr)
            continue

        print(answer)

if __name__ == "__main__":
    repl()